package inequivalent;

import org.junit.jupiter.api.Test;

import java.util.Vector;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;

class ClonePair143Method2Test {

    private final ClonePair143 subject = new ClonePair143();

    @Test
    void method2ReturnsIndexOfCaseInsensitiveMatch() {
        // Generated by Codex (gpt-5.4).
        Vector<String> genes = new Vector<>();
        genes.add("BRCA1");
        genes.add("TP53");

        assertEquals(0, subject.method2(genes, "brca1"));
    }

    @Test
    void method2ReturnsMinusOneWhenNoMatchExists() {
        // Generated by Codex (gpt-5.4).
        Vector<String> genes = new Vector<>();
        genes.add("BRCA1");

        assertEquals(-1, subject.method2(genes, "EGFR"));
    }

    @Test
    void method2ReturnsFirstMatchingIndexFromIteration() {
        // Generated by Codex (gpt-5.4).
        Vector<String> genes = new Vector<>();
        genes.add("TP53");
        genes.add("BRCA1");
        genes.add("tp53");

        assertEquals(0, subject.method2(genes, "Tp53"));
    }

    @Test
    void method2ThrowsNullPointerExceptionForNullSearchString() {
        // Generated by Codex (gpt-5.4).
        Vector<String> genes = new Vector<>();
        genes.add("TP53");

        assertThrows(NullPointerException.class, () -> subject.method2(genes, null));
    }
}
